// Generic helpers for resolving content paths, image references, and config values.

/**
 * Resolve a content path from a content object.
 * Supports dot-notation keys: "hero.headline" → content.hero.headline
 * Falls back to direct key access.
 */
export function resolveContent(content: Record<string, any> | null | undefined, key: string): any {
  if (!content || !key) return null
  let sc = content[key]
  if (!sc && key.includes('.')) sc = key.split('.').reduce((o: any, k: string) => o?.[k], content)
  return sc
}

/**
 * Resolve an image URL from an image manifest and a reference string.
 * Supports:
 *   - "@img:category.name" → image manifest path lookup
 *   - "@src:category.name" → same format, different prefix
 *   - plain URL string → returned as-is
 */
export function resolveImage(images: Record<string, any> | null | undefined, ref: string): string {
  if (!ref || !images) return ''
  if (ref.startsWith('@img:') || ref.startsWith('@src:')) {
    const key = ref.startsWith('@img:') ? ref.replace('@img:', '') : ref.replace('@src:', '')
    const parts = key.split('.')
    let obj: any = images
    for (const p of parts) {
      if (obj?.[p]) obj = obj[p]
      else return ''
    }
    return obj?.src || obj?.fallbackSrc || ''
  }
  return ref
}

/**
 * Resolve a config value with fallbacks and locale-awareness.
 * Tries: key → key_{locale} → defaultValue
 */
export function resolveConfig(
  obj: Record<string, any> | null | undefined,
  key: string,
  locale?: string,
  defaultValue?: string
): string {
  if (!obj) return defaultValue || ''
  return obj[`${key}_${locale}`] || obj[key] || defaultValue || ''
}

/**
 * Resolve a localized text field from a content block.
 * Tries: field_{locale} → field → ''
 */
export function localizedField(
  obj: Record<string, any> | null | undefined,
  field: string,
  locale?: string
): string {
  if (!obj) return ''
  return obj[`${field}_${locale}`] || obj[field] || ''
}", "exit_code": 0, "error": null}

{"output": "const fs = require('fs')
const path = require('path')

interface CacheEntry { data: any; timestamp: number }
const cache = new Map<string, CacheEntry>()
const TTL = 60_000

export function loadJSON(dir: string, file: string): any {
  const fullPath = path.join(dir, file)
  const now = Date.now()
  const cached = cache.get(fullPath)
  if (cached && (now - cached.timestamp) < TTL) return cached.data
  try {
    const data = JSON.parse(fs.readFileSync(fullPath, 'utf-8'))
    cache.set(fullPath, { data, timestamp: now })
    return data
  } catch { return null }
}

export function loadContentJSON(dir: string, file: string): any {
  const fullPath = path.join(dir, file)
  const cached = cache.get(fullPath)
  if (cached && (Date.now() - cached.timestamp) < TTL) return cached.data
  const data = loadJSON(dir, file)
  if (data) cache.set(fullPath, { data, timestamp: Date.now() })
  return data
}", "exit_code": 0, "error": null}

